import React from "react";
import CommonTable from "../../../components/CommonTable";

function SchemeMastersTable({ module }) {
   return (
      <div className="card border-0 shadow-sm">
         <div className="card-header border-0" style={{ background: module.bg, borderLeft: `5px solid ${module.color}` }} >
            <div className="d-flex align-items-center">
                <div><h5 className="card-title mb-0 fw-bold">
                  {module.listTitle}
               </h5><br />
               <small> All scheme types added to the system. </small></div>
            </div>
         </div>
         <div className="card-body text-center py-5" style={{ minHeight: "600px" }} >
            <h6>No data available.</h6>
         </div>
      </div>
   );
}

export default SchemeMastersTable;
